#include<bits/stdc++.h>
#define INF 0x3f3f3f3f
#define N 20002
#define mod 1000000007
using namespace std;
int n,m,r,size=0;
int to[N],ne[N],head[N],son[N],ans[50002],de[N];
void Connectitvity(int x,int y){to[++size]=y,ne[size]=head[x],head[x]=size;}
void dfs(int x,int fa){
	son[x]=1,de[x]=de[fa]+1;
	for(int i=head[x];i;i=ne[i]){
		if(to[i]!=fa){dfs(to[i],x),son[x]+=son[to[i]]%mod;}
	}
}
int f(int p){
	int x,y=0,z=0;z=x=son[p];
	for(int i=head[p];i;i=ne[i]){
		if(de[to[i]]<de[p])continue;
		y=son[to[i]],z+=(long long)((x-y)*y)%mod;
	}
	return z;
}
int main(void){
    cin>>n>>r>>m;
    for(int i=1;i<n;i++){
    	int x,y;cin>>x>>y;
    	Connectitvity(x,y),Connectitvity(y,x);
	}dfs(r,r);
	for(int i=1;i<=n;i++)ans[i]=f(i);
	for(int i=1;i<=m;i++){
		int p;cin>>p;
		cout<<ans[p]<<endl;
	}
	return 0;
}
